VALUES
  ('social-worker-moex-03051', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '就商品品質與社會服務品質特性做比較，下列何者是社會服務品質的特性之一：', '["產出和消費不同時間發生（可分離性）", "生產過程中服務使用者參與較少", "品質創造滿足和需求後可能造成資源排擠", "涉入的利害關係人及其動機較為單純"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03052', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列對於公關（public relations）與行銷（marketing）的敘述，何者是正確的？', '["公關不界定組織的目標，行銷則直接涉及到界定事務使命、顧客和服務", "相較於公關，行銷偏重於組織形象的經營，對組織之獲得外界的支持有非常重要的影響", "公關試圖影響特定的行為，行銷則企圖影響態度", "公關是一種溝通工具，也包括產品的發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03053', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務品質的那種觀點主張：「回應個別的需求，以及讓民眾具有做為公民和顧客的權力」？', '["科學觀點（scientific approach）", "卓越觀點（excellence approach）", "消費主義觀點（consumerist approach）", "民主觀點（democratic approach）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03054', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「社會工作管理」之有別於「社會工作行政」主要是在其：', '["注重體制面及系統程序面", "講求溝通、協調、合作", "注重執行面，具有命令、操作、統制之綜合機能", "僅依循法令、法律之規範與要求行事"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03055', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於「績效管理」的敘述，下列何者是正確的？', '["控制（Controlling）是「績效管理」之最佳方法", "「績效管理」係指對機構員工施以管理，以提高其服務效能之過程", "「績效管理」對服務目標之達成與否沒有影響性作用", "「績效評估」即是「績效管理」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03056', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於「協調」（Coordination）功能之敘述，下列何者為正確？', '["協調只是暫時性任務", "係為：彼此分工，密切配合", "只需確認自份應負責之工作", "若部屬能事事依照指示確切行事，就不需要協調"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03057', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於有機型結構（organic structure）的組織之敘述，下列何者是正確的？', '["明確的任務、角色與分工", "強調標準化作業", "強調個人適任、專業及創新能力", "重視組織的可預測性和穩定性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03058', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於激勵的雙因子理論（激勵－保健理論）的主張，下列敘述何者是正確的？', '["該理論假定：「工作滿足」的反面是「工作不滿足」", "當人們感覺工作滿足時，通常是與「外在因素」有關（如：工作條件、督導、人際關係）", "當人們感覺工作不滿足時，通常是與「內在因素」有關（如：成就、責任、成長）", "對於能防止不滿的因素，但卻不必然能產生激勵，稱之為「保健因素」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03059', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Kurt Lewin提出的組織變革三階段模式中，其步驟依序為：', '["變革→解凍→再結凍", "解凍→變革→再結凍", "再結凍→變革→解凍", "變革→再結凍→解凍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03060', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '若與非社會服務的契約做比較，下列何者是社會服務契約的特性之一？', '["工作要求較容易訂定", "長期性的方案結果較難確定及監督", "績效的監督著重在有形的任務或輸出", "任務通常較為標準化與定量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
